23→export function resolveReplyTargets({
24→  incomingJid,
25→  fromMe,
26→  meId,
27→  meLid,
28→  singleNumberMode,
29→  enableFallback,
30→  strategy = "dual_fallback",
31→}) {
32→  const primary = String(incomingJid || "").trim();
33→  if (!primary) {
34→    return { primary: "", fallbacks: [], strategy, reason: "missing_incoming" };
35→  }
36→
37→  if (!singleNumberMode || !fromMe) {
38→    return { primary, fallbacks: [], strategy, reason: "standard_mode" };
39→  }
40→
41→  if (!enableFallback || strategy !== "dual_fallback") {
42→    return { primary, fallbacks: [], strategy, reason: "fallback_disabled" };
43→  }
44→
45→  const incomingIsLid = Boolean(isLidUser(primary));
46→  const mePhoneJid = normalizePhoneJid(meId);
47→  const meLidJid = jidNormalizedUser(meLid || "");
48→
49→  if (incomingIsLid && mePhoneJid) {
50→    return {
51→      primary,
52→      fallbacks: unique([mePhoneJid, meLidJid].filter((j) => j && j !== primary)),
53→      strategy,
54→      reason: "lid_primary_phone_fallback",
55→    };
56→  }
57→
58→  const fallbackCandidates = [];
59→  if (meLidJid && meLidJid !== primary) {
60→    fallbackCandidates.push(meLidJid);
61→  }
62→
63→  return {
64→    primary,
65→    fallbacks: unique(fallbackCandidates),
66→    strategy,
67→    reason: "single_number_non_lid",
68→  };
69→}
