333→  async handleIncoming(input) {
334→    await this.gradeService.addConversation(
335→      input.userId,
336→      "user",
337→      input.text || `[attachment:${(input.attachments || []).map((a) => a.type).join(",")}]`,
338→    );
339→
340→    const confirmation = parseYesNo(input.text);
341→    if (confirmation) {
342→      const confirmationResult = await this.gradeService.handleConfirmation(
343→        { userId: input.userId },
344→        confirmation,
345→      );
346→      await this.gradeService.addConversation(
347→        input.userId,
348→        "assistant",
349→        confirmationResult.replyText,
350→      );
351→      return confirmationResult;
352→    }
353→
354→    const attachments = Array.isArray(input.attachments) ? input.attachments : [];
355→    if (attachments.length) {
356→      const image = attachments.find((a) => a.type === "image");
357→      if (image) {
358→        const imageResult = await this.handleImageAttachment(input, image);
359→        await this.gradeService.addConversation(
