  6→function parseModelJson(rawContent) {
  7→  const text = String(rawContent || "")
  8→    .replace(/<think>[\s\S]*?<\/think>/g, "")
  9→    .trim();
 10→  if (!text) {
 11→    throw new Error("Vision model returned empty output.");
 12→  }
 13→  try {
 14→    return JSON.parse(text);
 15→  } catch {
 16→    const firstBrace = text.indexOf("{");
 17→    const lastBrace = text.lastIndexOf("}");
 18→    if (firstBrace >= 0 && lastBrace > firstBrace) {
 19→      return JSON.parse(text.slice(firstBrace, lastBrace + 1));
 20→    }
 21→    throw new Error("Failed to parse JSON from vision output.");
 22→  }
