 44→export function createPythonBridge({ config, logger }) {
 45→  async function runPython(
 46→    scriptName,
 47→    payload,
 48→    { timeoutMs = 120000, retries = 0 } = {},
 49→  ) {
 50→    const scriptPath = path.join(config.python.scriptsDir, scriptName);
 51→    const [pythonCmd, ...pythonArgs] = splitCommand(config.python.bin);
 52→    const execOnce = () =>
 53→      new Promise((resolve, reject) => {
 54→        const child = spawn(pythonCmd, [...pythonArgs, scriptPath], {
 55→          stdio: ["pipe", "pipe", "pipe"],
 56→          cwd: config.paths.projectRoot,
 57→          env: process.env,
 58→        });
 59→
 60→        let stdout = "";
 61→        let stderr = "";
 62→        const timer = setTimeout(() => {
 63→          child.kill("SIGTERM");
 64→          reject(
 65→            new Error(`Python script timed out after ${timeoutMs}ms: ${scriptName}`),
 66→          );
 67→        }, timeoutMs);
 68→
 69→        child.stdout.on("data", (chunk) => {
 70→          stdout += chunk.toString();
 71→        });
 72→        child.stderr.on("data", (chunk) => {
 73→          stderr += chunk.toString();
 74→        });
 75→
 76→        child.on("error", (error) => {
 77→          clearTimeout(timer);
 78→          reject(error);
 79→        });
 80→
 81→        child.on("close", (code) => {
 82→          clearTimeout(timer);
 83→          if (code !== 0) {
 84→            reject(
 85→              new Error(
 86→                `Python script failed (${scriptName}) with code ${code}. stderr: ${stderr.trim()}`,
 87→              ),
 88→            );
 89→            return;
 90→          }
 91→          try {
 92→            const parsed = parseJsonOutput(stdout);
 93→            const validated = PythonResultSchema.parse(parsed);
 94→            resolve(validated);
 95→          } catch (error) {
 96→            reject(
 97→              new Error(
 98→                `Invalid JSON from Python (${scriptName}): ${error.message}. Raw: ${stdout.slice(0, 600)}`,
 99→              ),
100→            );
101→          }
102→        });
103→
104→        child.stdin.write(JSON.stringify(payload || {}));
105→        child.stdin.end();
106→      });
107→
108→    try {
109→      return await pRetry(execOnce, {
110→        retries,
111→        factor: 2,
112→        minTimeout: 400,
113→        maxTimeout: 3000,
114→        onFailedAttempt: (error) => {
115→          logger.warn(
116→            `Python bridge retry ${error.attemptNumber}/${error.retriesLeft + error.attemptNumber} for ${scriptName}: ${error.message}`,
117→          );
118→        },
119→      });
120→    } catch (error) {
121→      logger.error(`Python bridge error in ${scriptName}: ${error.message}`);
122→      throw error;
123→    }
124→  }
125→
126→  return { runPython };
127→}
